    section: "AUD",
    blueprintArea: "AUD-III",
    topic: "Audit Procedures",
    subtopic: "Analytical Procedures",
    difficulty: "medium",
    skillLevel: "Application",
    question: "During the completion phase of an audit, analytical procedures are:",
