    section: "AUD",
    blueprintArea: "AUD-III",
    topic: "Audit Procedures",
    subtopic: "Attorney Letters",
    difficulty: "hard",
    skillLevel: "Analysis",
    question: "An attorney's refusal to respond to the audit inquiry letter is:",
